                                          envoy::service::discovery::v3::DiscoveryResponse>>(\n        /*primary_stream_creator=*/\n        [&grpc_mux_context](\n            GrpcStreamCallbacks<envoy::service::discovery::v3::DiscoveryResponse>* callbacks)\n            -> GrpcStreamInterfacePtr<envoy::service::discovery::v3::DiscoveryRequest,\n                                      envoy::service::discovery::v3::DiscoveryResponse> {\n          return std::make_unique<GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,\n                                             envoy::service::discovery::v3::DiscoveryResponse>>(\n              callbacks, std::move(grpc_mux_context.async_client_),\n              grpc_mux_context.service_method_, grpc_mux_context.dispatcher_,\n              grpc_mux_context.scope_, std::move(grpc_mux_context.backoff_strategy_),\n              grpc_mux_context.rate_limit_settings_);\n        },\n        /*failover_stream_creator=*/\n        grpc_mux_context.failover_async_client_", "numLines": 100, "startLine": 1, "totalLines": 655}}

313→void GrpcMuxImpl::onDiscoveryResponse(
   314→    std::unique_ptr<envoy::service::discovery::v3::DiscoveryResponse>&& message,
   315→    ControlPlaneStats& control_plane_stats) {
   316→  const std::string type_url = message->type_url();
   317→  ENVOY_LOG(debug, "Received gRPC message for {} at version {}", type_url, message->version_info());
   318→
   319→  if (api_state_.count(type_url) == 0) {
   320→    // TODO(yuval-k): This should never happen. consider dropping the stream as this is a
   321→    // protocol violation
   322→    ENVOY_LOG(warn, "Ignoring the message for type URL {} as it has no current subscribers.",
   323→              type_url);
   324→    return;
   325→  }
   326→
   327→  ApiState& api_state = apiStateFor(type_url);
   328→
   329→  if (message->has_control_plane()) {
   330→    control_plane_stats.identifier_.set(message->control_plane().identifier());
   331→
   332→    if (message->control_plane().identifier() != api_state.control_plane_identifier_) {
   333→      api_state.control_plane_identifier_ = message->control_plane().identifier();
   334→      ENVOY_LOG(debug, "Receiving gRPC updates for {} from {}", type_url,
   335→                api_state.control_plane_identifier_);
   336→    }
   337→  }
   338→
   339→  if (api_state.watches_.empty()) {
   340→    // update the nonce as we are processing this response.
   341→    api_state.request_.set_response_nonce(message->nonce());
   342→    if (message->resources().empty()) {
   343→      // No watches and no resources. This can happen when envoy unregisters from a
   344→      // resource that's removed from the server as well. For example, a deleted cluster
   345→      // triggers un-watching the ClusterLoadAssignment watch, and at the same time the
   346→      // xDS server sends an empty list of ClusterLoadAssignment resources. we'll accept
   347→      // this update. no need to send a discovery request, as we don't watch for anything.
   348→      api_state.request_.set_version_info(message->version_info());
   349→    } else {
   350→      // No watches and we have resources - this should not happen. send a NACK (by not
   351→      // updating the version).
   352→      ENVOY_LOG(warn, "Ignoring unwatched type URL {}", type_url);
   353→      queueDiscoveryRequest(type_url);
   354→    }
   355→    return;
   356→  }
   357→  ScopedResume same_type_resume;
   358→  // We pause updates of the same type. This is necessary for SotW and GrpcMuxImpl, since unlike
   359→  // delta and NewGRpcMuxImpl, independent watch additions/removals trigger updates regardless of
   360→  // the delta state. The proper fix for this is to converge these implementations,
   361→  // see https://github.com/envoyproxy/envoy/issues/11477.
   362→  same_type_resume = pause(type_url);
   363→  TRY_ASSERT_MAIN_THREAD {
   364→    std::vector<DecodedResourcePtr> resources;
   365→    OpaqueResourceDecoder& resource_decoder = *api_state.watches_.front()->resource_decoder_;
   366→
   367→    for (const auto& resource : message->resources()) {
   368→      // TODO(snowp): Check the underlying type when the resource is a Resource.
   369→      if (!resource.Is<envoy::service::discovery::v3::Resource>() &&
   370→          type_url != resource.type_url()) {
   371→        throw EnvoyException(
   372→            fmt::format("{} does not match the message-wide type URL {} in DiscoveryResponse {}",
   373→                        resource.type_url(), type_url, message->DebugString()));
   374→      }
   375→
   376→      auto decoded_resource =
   377→          DecodedResourceImpl::fromResource(resource_decoder, resource, message->version_info());
   378→
   379→      if (!isHeartbeatResource(type_url, *decoded_resource)) {
   380→        resources.emplace_back(std::move(decoded_resource));
   381→      }
   382→    }
   383→
   384→    processDiscoveryResources(resources, api_state, type_url, message->version_info(),
   385→                              /*call_delegate=*/true);
   386→
   387→    // Processing point when resources are successfully ingested.
   388→    if (xds_config_tracker_.has_value()) {
   389→      xds_config_tracker_->onConfigAccepted(type_url, resources);
   390→    }
   391→  }
   392→  END_TRY
   393→  catch (const EnvoyException& e) {
   394→    for (auto watch : api_state.watches_) {
   395→      watch->callbacks_.onConfigUpdateFailed(
   396→          Envoy::Config::ConfigUpdateFailureReason::UpdateRejected, &e);
   397→    }
   398→    ::google::rpc::Status* error_detail = api_state.request_.mutable_error_detail();
   399→    error_detail->set_code(Grpc::Status::WellKnownGrpcStatus::Internal);
   400→    error_detail->set_message(Config::Utility::truncateGrpcStatusMessage(e.what()));
   401→
   402→    // Processing point when there is any exception during the parse and ingestion process.
   403→    if (xds_config_tracker_.has_value()) {
   404→      xds_config_tracker_->onConfigRejected(*message, error_detail->message());
   405→    }
   406→  }
   407→  api_state.previously_fetched_data_ = true;
   408→  api_state.request_.set_response_nonce(message->nonce());
   409→  ASSERT(api_state.paused());
   410→  queueDiscoveryRequest(type_url);
   411→}
