    22→      ttl_(
    23→          [this](const auto& expired) {
    24→            Protobuf::RepeatedPtrField<std::string> removed_resources;
    25→            for (const auto& resource : expired) {
    26→              if (auto maybe_resource = getRequestedResourceState(resource);
    27→                  maybe_resource.has_value()) {
    28→                maybe_resource->setAsWaitingForServer();
    29→                removed_resources.Add(std::string(resource));
    30→              } else if (const auto erased_count = wildcard_resource_state_.erase(resource) +
    31→                                                   ambiguous_resource_state_.erase(resource);
    32→                         erased_count > 0) {
    33→                removed_resources.Add(std::string(resource));
    34→              }
    35→            }
    36→
    37→            watch_map_.onConfigUpdate({}, removed_resources, "");
    38→          },
    39→          dispatcher, dispatcher.timeSource()),
